 1	import React from 'react';
 2	
 3	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { isEmpty } from '@kubevirt-utils/utils/utils';
 6	import { Bullseye, Card, Grid, GridItem } from '@patternfly/react-core';
 7	
 8	import useMetricChartData from '../utils/hooks/useMetricChartData';
 9	import { ChartCardProps } from '../utils/types';
10	import { getCurrentValue } from '../utils/utils';
11	
12	import MetricChart from './MetricChart';
13	
14	import './ChartCard.scss';
15	
16	const ChartCard: React.FC<ChartCardProps> = ({ metric }) => {
17	  const { t } = useKubevirtTranslation();
18	  const metricChartData = useMetricChartData(metric);
19	  const { chartData, isReady, numberOfTicks, unit } = metricChartData;
20	  const currentValue = getCurrentValue(chartData);
21	  const chartLabel = t("Last {{numOfDays}} days' trend", { numOfDays: numberOfTicks });
22	  const metricLabel = unit && isReady ? `${metric} (${unit})` : metric;
23	  const metricValue = currentValue && !isNaN(currentValue) ? currentValue?.toLocaleString() : 0;
24	
25	  return (
26	    <Card className="metric-chart-card">
27	      <Grid className="metric-chart-card__content">
28	        <GridItem className="metric-chart-card__header">
29	          <div className="metric-chart-card__header--current-value">
30	            <span className="metric-chart-card__header--value">{metricValue}</span>
31	          </div>
32	          <div className="metric-chart-card__header--metric">{metricLabel}</div>
33	        </GridItem>
34	        <GridItem className="metric-chart-card__chart">
35	          {isReady ? (
36	            <span>
37	              <div className="metric-chart-card__chart--label">{chartLabel}</div>
38	              <div className="metric-chart-card__chart--chart">
39	                <MetricChart metric={metric} metricChartData={metricChartData} />
40	              </div>
41	            </span>
42	          ) : (
43	            <Bullseye>
44	              <MutedTextSpan
45	                text={
46	                  isEmpty(chartData)
47	                    ? t('No data available')
48	                    : t(
49	                        'VMs in this namespace are new, therefore not enough data is collected to display a graph.',
50	                      )
51	                }
52	              />
53	            </Bullseye>
54	          )}
55	        </GridItem>
56	      </Grid>
57	    </Card>
58	  );
59	};
60	
61	export default ChartCard;

